import React, { useEffect, useState } from "react";
import { getProducts, createProduct } from "../api";

export default function Products() {
  const [products, setProducts] = useState([]);
  const [form, setForm] = useState({ name: "", category: "" });

  // 🔥 FETCH PRODUCTS
  const fetchProducts = async () => {
    try {
      const data = await getProducts();
      console.log("PRODUCTS API:", data); // 🔍 debug

      // 🔥 HANDLE DIFFERENT RESPONSE SHAPES
      const list = Array.isArray(data)
        ? data
        : Array.isArray(data?.products)
        ? data.products
        : Array.isArray(data?.data)
        ? data.data
        : [];

      // 🔥 NORMALIZE FIELDS
      const formatted = list.map((p) => ({
        id: p.product_id || p.id,
        name: p.name || p.product_name,
        category: p.category || "General",
      }));

      setProducts(formatted);

    } catch (err) {
      console.error("Error fetching products:", err);
      alert("Failed to load products");
      setProducts([]);
    }
  };

  useEffect(() => {
    fetchProducts();
  }, []);

  // 🔥 ADD PRODUCT
  const addProduct = async () => {
    if (!form.name || !form.category) {
      alert("Fill all fields");
      return;
    }

    try {
      const res = await createProduct(form);
      console.log("ADD PRODUCT:", res); // 🔍 debug

      setForm({ name: "", category: "" });

      // 🔥 FORCE REFRESH AFTER ADD
      await fetchProducts();

    } catch (err) {
      console.error("Error adding product:", err);
      alert("Failed to add product");
    }
  };

  return (
    <div className="p-6 space-y-6">
      <h1 className="text-2xl font-bold">Products</h1>

      {/* FORM */}
      <div className="bg-white/10 p-4 rounded grid md:grid-cols-3 gap-3">
        <input
          placeholder="Name"
          value={form.name}
          onChange={(e) => setForm({ ...form, name: e.target.value })}
          className="p-2 bg-white/10 rounded"
        />

        <input
          placeholder="Category"
          value={form.category}
          onChange={(e) => setForm({ ...form, category: e.target.value })}
          className="p-2 bg-white/10 rounded"
        />

        <button
          onClick={addProduct}
          className="bg-green-600 text-white rounded"
        >
          Add
        </button>
      </div>

      {/* LIST */}
      {products.length === 0 ? (
        <p>No products found</p>
      ) : (
        products.map((p) => (
          <div key={p.id} className="bg-white/10 p-3 rounded">
            {p.name} ({p.category})
          </div>
        ))
      )}
    </div>
  );
}
